+function drawSaldoChart(fluxos) {
+  const canvas = document.querySelector("#grafico-saldo");
+  if (!canvas) return;
+  const ctx = canvas.getContext("2d");
+  const entries = Object.entries(fluxos).sort((a, b) => (a[0] > b[0] ? 1 : -1));
+  const values = entries.map(([, f]) => f.receita - f.despesa);
+
+  const width = canvas.clientWidth || 600;
+  const height = Number(canvas.getAttribute("height")) || 180;
+  canvas.width = width;
+  canvas.height = height;
+
+  ctx.clearRect(0, 0, width, height);
+  ctx.fillStyle = "#11172a";
+  ctx.fillRect(0, 0, width, height);
+
+  if (values.length === 0) {
+    ctx.fillStyle = "#9aa6c5";
+    ctx.fillText("Sem dados para grafico.", 12, 28);
+    return;
+  }
+
+  const min = Math.min(0, ...values);
+  const max = Math.max(0, ...values);
+  const range = Math.max(1, max - min);
+  const pad = 24;
+  const step = values.length > 1 ? (width - pad * 2) / (values.length - 1) : 0;
+
+  const yPos = (v) => height - pad - ((v - min) / range) * (height - pad * 2);
+  const xPos = (i) => pad + i * step;
+
+  ctx.strokeStyle = "#2b3964";
+  ctx.beginPath();
+  ctx.moveTo(pad, yPos(0));
+  ctx.lineTo(width - pad, yPos(0));
+  ctx.stroke();
+
+  ctx.strokeStyle = "#6e8bff";
+  ctx.lineWidth = 2;
+  ctx.beginPath();
+  values.forEach((v, i) => {
+    if (i === 0) ctx.moveTo(xPos(i), yPos(v));
+    else ctx.lineTo(xPos(i), yPos(v));
+  });
+  ctx.stroke();
+
+  ctx.fillStyle = "#eff3ff";
+  values.forEach((v, i) => {
+    const x = xPos(i);
+    const y = yPos(v);
+    ctx.beginPath();
+    ctx.arc(x, y, 3, 0, Math.PI * 2);
+    ctx.fill();
+  });
 }
