+function calculateMonthlyScore(receitas, despesas) {
+  if (receitas <= 0) return 0;
+  const savingsRate = ((receitas - despesas) / receitas) * 100;
+  const budgets = state.orcamentos.length;
+  const estourados = state.orcamentos.filter((o) => {
+    const gasto = state.transacoes
+      .filter(
+        (t) =>
+          t.tipo === "despesa" &&
+          t.categoria.toLowerCase() === String(o.categoria).toLowerCase() &&
+          monthKey(t.data) === currentMonthKey()
+      )
+      .reduce((acc, t) => acc + Number(t.valor), 0);
+    return gasto > Number(o.limite);
+  }).length;
+  const budgetPenalty = budgets > 0 ? (estourados / budgets) * 20 : 0;
+  const score = Math.max(0, Math.min(100, 65 + savingsRate * 0.7 - budgetPenalty));
+  return Math.round(score);
+}
